import json
import pymysql

def lambda_handler(event, context):
    # RDS credentials and details are hidden here
    db_user = "your-db-username"
    db_pass = "your-db-password"
    db_name = "your-database-name"
    db_host = "your-db-endpoint"
    
    # Connect to the database
    conn = pymysql.connect(db_host, user=db_user, passwd=db_pass, db=db_name)
    cursor = conn.cursor()
    
    if event:
        query_params = []
        sql = "SELECT * FROM products WHERE 1=1"
        
        # Build SQL dynamically based on the provided parameters
        if 'productId' in event['queryStringParameters']:
            product_id = event['queryStringParameters']['productId']
            query_params.append(product_id)
            sql += " AND id = %s"
        
        if 'productName' in event['queryStringParameters']:
            product_name = event['queryStringParameters']['productName']
            query_params.append(product_name)
            sql += " AND name = %s"
            
        # Execute the SQL and fetch all results
        cursor.execute(sql, tuple(query_params))
        
    response = {
        'statusCode': 200,
        'body': json.dumps(cursor.fetchall())
    }
    
    return response